/**
 * Snapshot tests for the core REST OpenAPI projection.
 *
 * `openapi/core.openapi.json` is the ts-rest projection of
 * `src/contract/rest.ts` (generated by `scripts/generate-openapi.ts`). It
 * supersedes the previous tRPC-era snapshot: during the core REST migration
 * the document grows one domain at a time as each tRPC slice converts. The
 * `git diff --exit-code` drift check in `core-quality.yml` is the canonical
 * up-to-date guard; this suite locks in the structural invariants (3.x
 * version, info block, every operation has a summary + operationId) and the
 * shape of the migrated `entities` domain.
 */
import { readFileSync } from 'node:fs';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

import { describe, expect, it } from 'vitest';

interface Operation {
  summary?: string;
  operationId?: string;
}

interface OpenApiDocument {
  openapi: string;
  info: { title: string; version: string };
  paths: Record<string, Record<string, Operation>>;
  components?: { schemas?: Record<string, unknown> };
}

const here = dirname(fileURLToPath(import.meta.url));
const openapiPath = resolve(here, '..', '..', '..', 'openapi', 'core.openapi.json');
const openapi = JSON.parse(readFileSync(openapiPath, 'utf8')) as OpenApiDocument;

describe('@pops/core REST openapi projection', () => {
  it('declares an OpenAPI 3.x version', () => {
    expect(openapi.openapi).toMatch(/^3\./);
  });

  it('has an info block identifying the core pillar contract', () => {
    expect(openapi.info.title).toBe('@pops/core');
    expect(openapi.info.version).toMatch(/^\d+\.\d+\.\d+/);
  });

  it('exposes at least one path', () => {
    expect(Object.keys(openapi.paths).length).toBeGreaterThan(0);
  });

  it('every documented operation has a summary and operationId', () => {
    for (const [path, methods] of Object.entries(openapi.paths)) {
      for (const [method, operation] of Object.entries(methods)) {
        expect(operation.summary, `${method} ${path} missing summary`).toBeTruthy();
        expect(operation.operationId, `${method} ${path} missing operationId`).toBeTruthy();
      }
    }
  });

  it.each([
    ['GET', '/entities', 'entities.list'],
    ['POST', '/entities', 'entities.create'],
    ['GET', '/entities/{id}', 'entities.get'],
    ['PATCH', '/entities/{id}', 'entities.update'],
    ['DELETE', '/entities/{id}', 'entities.delete'],
  ])('describes the %s %s endpoint with operationId %s', (method, path, operationId) => {
    const op = openapi.paths[path]?.[method.toLowerCase()];
    expect(op, `${method} ${path} should be documented`).toBeDefined();
    expect(op?.operationId).toBe(operationId);
  });

  it.each([
    ['GET', '/features/manifests', 'features.getManifests'],
    ['GET', '/features', 'features.list'],
    ['GET', '/features/{key}/enabled', 'features.isEnabled'],
    ['PUT', '/features/{key}/enabled', 'features.setEnabled'],
    ['PUT', '/features/{key}/preference', 'features.setUserPreference'],
    ['DELETE', '/features/{key}/preference', 'features.clearUserPreference'],
  ])('describes the %s %s endpoint with operationId %s', (method, path, operationId) => {
    const op = openapi.paths[path]?.[method.toLowerCase()];
    expect(op, `${method} ${path} should be documented`).toBeDefined();
    expect(op?.operationId).toBe(operationId);
  });

  it('documents only the migrated REST domains, not the tRPC surface', () => {
    // The set of tRPC slices converted to ts-rest so far. Grows one domain at
    // a time as the core REST migration proceeds; every documented path must
    // live under one of these roots.
    const MIGRATED_DOMAIN_ROOTS = [
      '/entities',
      '/users',
      '/shell',
      '/ai-usage',
      '/ai-budgets',
      '/ai-providers',
      '/ai-observability',
      '/ai-alerts',
      '/settings',
      '/service-accounts',
      '/search',
      '/features',
    ];
    const paths = Object.keys(openapi.paths);
    for (const p of paths) {
      expect(
        MIGRATED_DOMAIN_ROOTS.some((root) => p === root || p.startsWith(`${root}/`)),
        `${p} is not under a migrated domain root`
      ).toBe(true);
    }
    // The legacy tRPC-era `/core/*` snapshot must be gone — this ts-rest
    // projection describes only the migrated REST domains.
    expect(paths.some((p) => p.startsWith('/core/'))).toBe(false);
  });
});
